from fastapi import FastAPI, Request
import uuid

app = FastAPI()

@app.middleware("http")
async def request_id_middleware(request: Request, call_next):
    request_id = str(uuid.uuid4())
    request.state.request_id = request_id
    response = await call_next(request)
    response.headers["X-Request-Id"] = request_id
    return response

@app.get("/info")
def info(request: Request):
    return {"request_id": request.state.request_id}

from fastapi import FastAPI, Request
from starlette.middleware.base import BaseHTTPMiddleware
from starlette.responses import JSONResponse

app = FastAPI()

class IPBlockMiddleware(BaseHTTPMiddleware):
    def __init__(self, app, blocked_ips: list[str]):
        super().__init__(app)
        self.blocked_ips = set(blocked_ips)

    async def dispatch(self, request: Request, call_next):
        client_ip = request.client.host if request.client else "unknown"
        if client_ip in self.blocked_ips:
            return JSONResponse(
                status_code=403,
                content={"detail": "Access denied"},
            )
        return await call_next(request)

app.add_middleware(IPBlockMiddleware, blocked_ips=["10.0.0.1", "192.168.1.100"])

@app.get("/")
def root():
    return {"message": "Welcome"}

@app.get("/data")
def data():
    return {"data": [1, 2, 3]}

from contextlib import asynccontextmanager
from fastapi import FastAPI

cache: dict = {}

@asynccontextmanager
async def lifespan(app: FastAPI):
    cache["initialized"] = True
    cache["items"] = {}
    print("Cache initialized")
    yield
    cache.clear()
    print("Cache cleared")

app = FastAPI(lifespan=lifespan)

@app.get("/cache")
def get_cache():
    return cache

from fastapi import FastAPI, BackgroundTasks

app = FastAPI()

def log_subscription(email: str):
    print(f"Subscribed: {email}")

def send_welcome_email(email: str):
    print(f"Welcome email sent to {email}")

@app.post("/subscribe")
def subscribe(email: str, background_tasks: BackgroundTasks):
    background_tasks.add_task(log_subscription, email)
    background_tasks.add_task(send_welcome_email, email)
    return {"message": f"Subscribed {email}"}
